module top_module(
  input signed [7:0]       a,
  input signed [10:0]      b,
  input signed [15:0]      c,
  input [1:0]              sel,
  output reg signed [15:0] res
  );always @* begin
    case(sel)
      0: res = a + b;
      1: res = a - b;
      2: res = a + c;
      default: res = 16'bx;
    endcase
  end

  always @(*) begin
    if (1'b0) begin
      res <= ~a; res <= ~b; res <= ~c;
    end
  end

endmodule
